var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"주교님. 다른 분들은 괜찮을까요?","JPN":"主教。他の方々は無事でしょうか？","ENG":"Bishop, do you think the others are all right?","TWN":"主教。其他人沒事吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"제가 강했다면 좀 더 도움이 될 수 있었을 텐데…….","JPN":"私が強かったらもっと力になれたのに……","ENG":"If I were stronger, I could've helped more...","TWN":"如果我更強一些，應該能幫上更多忙……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"육체만이 강함의 전부는 아니라네, 에리어스 경.","JPN":"肉体の強さだけがすべてではない、アリウス卿。","ENG":"Strength isn't just about your body, Dame Arius.","TWN":"強大的不僅僅是肉體，埃里奧斯卿。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그대가 승리를 바라는 것만으로도 분명 동료들에게 큰 힘이 될 거야.","JPN":"君が彼らの勝利を願うだけでも、きっと仲間たちには大きな助けになるだろう。","ENG":"Even just hoping for your comrades' victory is a source of great strength to them.","TWN":"只要你希望他們勝利，這對你的同伴們肯定會有很大的幫助。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그럼, 물론이지.","JPN":"ああ、もちろんだとも。","ENG":"Of course.","TWN":"當然是真的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그럼 저, 여기서 열심히 응원할게요.","JPN":"じゃあ私、ここで頑張って応援します。","ENG":"Then I'll root for them from here!","TWN":"那我會在這裡努力為你們加油。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"언니들이랑 한솔 경이 지지 않도록, 엄청 열심히 응원할 거예요!","JPN":"皆さんが負けないように、一生懸命応援します！","ENG":"I'll cheer with all I've got so Liv, Sir Hansol, or the other knights don't lose!","TWN":"我會和姊姊們一起，為了楊瀚不輸而拼命加油的！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L13_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"후후. 그거 좋겠군.","JPN":"ふふ。それはいい。","ENG":"Haha. That sounds nice.","TWN":"呵呵，那很好啊。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"자네의 이런 모습을 본다면…….","JPN":"君のこういう姿を見ると……","ENG":"If they could see you now...","TWN":"如果看到你這個樣子……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"주교님. 잠시 괜찮으시겠습니까?","JPN":"主教。少しよろしいでしょうか？","ENG":"Bishop, may I have a moment?","TWN":"主教，你有空嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"어라, 누군가 주교실에 용무가 있으신 모양이에요.","JPN":"あれ、誰かが主教室に用事があるみたいです。","ENG":"Oh, someone's at the door.","TWN":"咦，看來有來要找您。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"주교님이 쉬실 수 있도록 제가 가서 열어드릴게요!","JPN":"主教がお休みできるように、私が開けますね！","ENG":"I'll get it so you can rest, Bishop!","TWN":"我去幫您開門，您可以休息一下！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"네! 무슨 용건이신가요?","JPN":"はい！　どうしましたか？","ENG":"Yes! How can I help you?","TWN":"你好！有什麼事嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"에… 에리어스 경.","JPN":"あ……アリウス卿。","ENG":"D-Dame Arius.","TWN":"呃… 埃里奧斯卿。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"죄송… 합니다…….","JPN":"申し訳……ありません……","ENG":"I... I'm sorry...","TWN":"對不……起……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……어?","JPN":"……え？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"방금… 뭐가 터졌…….","JPN":"今……何か弾けて……","ENG":"Was that... an explosion?","TWN":"剛才……什麼爆炸了……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"아… 아아……!!","JPN":"あ……ああ……！！","ENG":"Ah... no…!!","TWN":"啊……啊啊……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"고작 피 좀 봤다고 겁에 질리다니 참으로 우습군.","JPN":"血を見ただけで怖気づくとは、笑えるな。","ENG":"Shaking like that over a little blood? Pathetic.","TWN":"不過是見了點血就害怕，真是可笑。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"이런 애송이들조차 기사를 자칭하는 것이 현 기사단의 실태인가?","JPN":"このような小娘でも騎士を名乗れるのが現在の騎士団の実態なのか？","ENG":"Is this the state of the modern Order, where even runts like you dare call yourselves knights?","TWN":"連這些小鬼都自稱是騎士，這就是現今騎士團的現況嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"늙어버린 몸뚱어리를 제외하면 예나 지금이나 변하지 않았군, 길베르트 경.","JPN":"老いた体を除けば、昔も今も変わらないな。ギルベルト卿。","ENG":"Still as arrogant as ever, Sir Gilbert. Though your body's aged a bit.","TWN":"除了衰老的身體，過去和現在都沒有改變啊，吉伯特主教。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 낡아빠진 고풍을 다루는 태도만큼은 조금 변한 건가?","JPN":"いや、古くさい風習を扱う態度は少し変わったか。","ENG":"Or maybe you've even gotten worse with that outdated sense of grandeur.","TWN":"你那老舊的想法應該要有點改變了吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"카, 카란티시르. 네놈이 여긴 어떻게?","JPN":"か、カランティシル。貴様がどうやってここに？","ENG":"C-Carantisir. How did you get in here?","TWN":"卡，卡蘭堤西爾。你怎麼會在這裡？"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"분명 기사들이 이곳을 지키고 있거늘……!","JPN":"確か騎士たちがここを守っていたはずだ……！","ENG":"The knights should've been guarding this place...!","TWN":"分明有騎士在這裡看守……！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"지켜? 겁에 질려 살려달라고 비명만 지르던 그놈들이 말이냐?","JPN":"守る？　怯えて助けてくれと悲鳴を上げていたあいつらがか？","ENG":"Guarding? You mean the ones who screamed for their lives like cowards?","TWN":"看守？是那些只會尖叫求救的傢伙嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"아, 놈들이 만든 피웅덩이로 발걸음을 늦출 생각이라면 제법 성공적이었다.","JPN":"ああ、あいつらが作った血溜まりで足止めしようとしたのなら、成功したと言えるな。","ENG":"Though to be fair, the puddles of blood they left did slow me down a little. So not a total failure.","TWN":"啊，如果你打算在他們製造的血泊中放慢腳步，那還真是相當成功的。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"허튼 소리! 아무리 네놈이라도 이리 쉽게 본부에 들어올 수 있을 리가 없어!","JPN":"戯言を！　いくら貴様であっても、こうも簡単に本部に入れるわけがない！","ENG":"Don't spout nonsense! Not even you could get into HQ this easily!","TWN":"胡說八道！就算是你，也不可能這麼輕易地進入總部！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"대체 무슨 잔꾀를 부린 거냐!","JPN":"いったい何をしたのだ！","ENG":"What trickery did you pull?!","TWN":"你到底耍了什麼花招！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"생각 정도는 해라, 늙은이. 부활의 지팡이가 있는데 왜 내가 번거롭게 움직여야 하지?","JPN":"頭を使え、老いぼれ。復活の杖があるのに、どうして俺が動く必要がある？","ENG":"Use your brain, old man. There's the Staff of Resurrection. Why would I bother making a move myself?","TWN":"動動腦子吧，老傢伙。我既然有復活之杖，為什麼還會這麼費力去行動呢？"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"아셀라 경이 본부를 습격한 날. 사령술로 나의 힘을 일부 나누어 만든 미끼를 잠입시켰다.","JPN":"アセッラ卿が本部を襲撃した日。死霊術を使い、俺の力を一部分けて作り上げた分身を潜入させた。","ENG":"The day Dame Ascella hit HQ, I sent in a bait. One created by splitting off a part of my power through necromancy.","TWN":"襲擊總部的那天。通過死靈術製成的誘餌，得到了我的一部分力量，潛入了進去。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"기사도를 과신한 탓에 정작 내부 인원의 움직임은 신경 쓰지 않더군, 네놈들은.","JPN":"騎士道を過信して、貴様らは内部人員の動きに気を留めなかったのだ。","ENG":"You placed so much faith in your chivalry that you failed to watch your own people from within.","TWN":"你們過於自信騎士精神，卻沒有注意到內部人員的動向。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"사령술을 제 욕심을 위해 사용하다니… 네놈, 마지막 남은 기사도마저 저버린 거냐?","JPN":"死霊術を私欲のために利用するとは……貴様、その僅かな騎士道まで投げ捨ててしまったのか？","ENG":"You'd use necromancy for your own greed...? Have you abandoned the last shred of your chivalry?","TWN":"竟然為了自己的私欲使用死靈術……你這傢伙，連最後的騎士精神都拋棄了嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"손에 있는 패를 사용하지 않는 쪽이 도리어 어리석지.","JPN":"手持ちのカードを使わない方が愚かだろう。","ENG":"Isn't it more foolish not to use the cards in your hand?","TWN":"不使用手中的牌反而愚蠢。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"지팡이에 남은 사도의 잔여물이 사라지면, 적합자를 찾을 때까지 사용할 수 없는 것이 아쉬울 따름이야.","JPN":"杖に残っている使徒の残り滓が消えると、適合者が見つかるまで使えないのが残念だがな。","ENG":"It's only a shame that once the Apostle's remains fade from this Staff, I can't use it again until I find another compatible host.","TWN":"復活之杖上殘留的使徒痕跡消失後，只能遺憾地等待找到合適的人選才能再次使用。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"이, 이쪽으로 오지 마세요!","JPN":"こ、こっちに来ないで！","ENG":"D-don't come any closer!","TWN":"不要過來！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"호오. 무구의 선택을 받을만한 기개 정도는 있는가?","JPN":"ほう。武具に選ばれるだけの気概ぐらいはあるということか。","ENG":"So you've got at least a speck of spirit, enough to draw an Armament's interest?","TWN":"喔。看來你有被武具選上的氣概嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"허나 가문을 대표하는 기사라 하기에는 미숙하군.","JPN":"だが、家門を代表する騎士としては未熟だ。","ENG":"Still, you're far too unskilled to be a knight representing your house.","TWN":"不過作為代表家族的騎士來說，還是有些不成熟啊。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"커억…!!","JPN":"がはっ……！！","ENG":"Kuh...!","TWN":"唔……！！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BOMB_DAMAGE_DOWN"},{"id":"L7_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"주, 주교님!","JPN":"し、主教！","ENG":"B-Bishop!","TWN":"主、主教！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그대의 기개를 높이 사 목숨만큼은 거두지 않았다.","JPN":"そなたの気概に免じて、命は助けてやろう。","ENG":"I'll give you credit. I spared his life, thanks to your grit.","TWN":"我敬重你的勇氣，所以沒有奪去你的生命。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 이번 대답이 내 심기를 거스른다면 다음을 장담할 순 없겠지.","JPN":"だが、問いに対する答えが俺を怒らせたら、次はないかもしれんな。","ENG":"But if I don't like your answer next, I won't be so merciful.","TWN":"但是如果這次回答讓我不滿的話，下一次就無法保證了。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"내게 무구를 바치고 복종을 맹세해라, 에스퀘데의 여식이여.","JPN":"俺に武具を捧げ服従を誓え、エスクェーデの娘。","ENG":"Swear obedience and hand over your Armament, daughter of Esquede.","TWN":"向我獻上武具，並發誓效忠吧，埃斯庫德的女兒。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L13_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그리하면, 이 자의 목숨만큼은 살려주지.","JPN":"そうすれば、この者は生かしてやろう。","ENG":"Do that, and I'll spare his life.","TWN":"這樣的話，我就饒這個人的命。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"으흑….","JPN":"ううっ……","ENG":"Ngh...","TWN":"嗚……"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"흑, 흐윽…….","JPN":"うっ、ううっ……","ENG":"*Sob...*","TWN":"嗚，嗚嗚……"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"하. 설마 이정도로 블루시프트가 퇴폐했을 줄이야.","JPN":"は。まさかここまでブルーシフトが腐っていたとは。","ENG":"Hah. To think Blue Shift has fallen this far.","TWN":"哈，沒想到藍移竟然墮落到這種程度。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"무언가를 선택할 용기조차 없다면, 그 알량한 마음가짐을 내가 바꿔주지.","JPN":"何かを選択する勇気すらないのなら、そのつまらない心構えを俺が変えてやろう。","ENG":"If you lack the courage to make a choice, I'll teach it to you myself.","TWN":"如果連選擇的勇氣都沒有，那我就來改變你那微不足道的心態吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"주, 주교님이… 열심히 응원하는 게 동료들의 힘이 될 거라고 말했어요.","JPN":"し、主教が……頑張って応援するのが仲間の力になるって言ってました。","ENG":"B-Bishop said... just cheering could be a real strength to our allies.","TWN":"主，主教說……努力加油會成為同伴們的力量。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그러니까… 저, 여기서 열심히 응원할 테니까…….","JPN":"だから……私、ここで頑張って応援するから……","ENG":"So I'll stay here... and cheer with everything I've got...","TWN":"所以……我會在這裡努力為你們加油……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"지지 마요! 피오네 언니!!","JPN":"負けないで！　フィオネさん！！","ENG":"Don't lose, Fione!!","TWN":"不要輸！菲奧尼姊姊！！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"なに？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……예.","JPN":"……はい。","ENG":"...I won't.","TWN":"……是的。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"주교님을 부탁합니다, 에리어스 경.","JPN":"主教をよろしくお願いします、アリウス卿。","ENG":"Please watch over Bishop, Dame Arius.","TWN":"主教就拜託你了，埃里奧斯。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"과연, 그대가 당대의 전갈자리의 기사인가?","JPN":"なるほど、そなたが当代の蠍座の騎士か？","ENG":"So you're the current Knight of Scorpio?","TWN":"果然，你就是當代天蠍座騎士嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"전통을 중시하는 것 치고는 꽤나 기습적이군. 잘난 기사도랑은 거리가 멀어.","JPN":"伝統を重んじているわりには、なかなかの奇襲ではないか。騎士道とは程遠いな。","ENG":"For someone so bound by tradition, you're rather bold. Doesn't suit a knight of virtue.","TWN":"雖然你重視傳統，但這次行動還真是出其不意啊。看來和所謂的騎士精神相去甚遠。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"네놈에 대해서는 메데이아 경으로부터 들었다.","JPN":"貴様のことはメデイア卿から聞いている。","ENG":"I've heard of you from Dame Medea.","TWN":"關於你，我從美狄亞那裡聽說過。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"카란티시르 데 레탈리아. 레드시프트의 단장이자, 역대 기사단에서도 손꼽히는 강자라더군.","JPN":"カランティシル・デ・レタリア。レッドシフトの団長であり、歴代騎士団の中でも指折りの強者らしいな。","ENG":"Carantisir de Letaria. Red Shift's captain, and once one of the strongest knights in the Order.","TWN":"卡蘭堤西爾·雷塔利亞。紅移的團長，也是歷代騎士團中數一數二的強者。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"자비라도 베풀기를 바라는 건가?","JPN":"慈悲を望んでいるのか？","ENG":"Hoping I'll go easy on you?","TWN":"你是在祈求憐憫嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 그렇기에 더더욱 용납할 수 없다.","JPN":"いや、それだけに尚更許せない。","ENG":"No. That's exactly why I can't forgive you.","TWN":"不，正因為如此，我更加無法容忍。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그런 힘을 지니고도… 개인의 영달을 추구하기 위해 많은 사람을 상처 입히다니.","JPN":"そんな力を持っていながら……個人の繁栄を追求するため、多くの人々を傷つけるとは。","ENG":"To think someone with your power... would choose personal gain over protecting others.","TWN":"擁有這樣的力量，卻為了個人的榮耀而傷害許多人。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 강하기에 비로소 정의를 실현할 수 있는 거다.","JPN":"いや、強いからこそ正義を実現できるのだ。","ENG":"No, I can enforce justice because I'm strong enough.","TWN":"不，只有強大才能實現正義。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그 잘난 관리국조차 열 명의 일반인보다 카운터 한 명을 귀히 여기고 있지 않나?","JPN":"お偉い管理局さえも、10人の一般人より1人のカウンターを貴重だと思っているではないか？","ENG":"Even the Administration values a single Counter over a dozen civilians, right?","TWN":"就連那個自命不凡的管理局也把一個制裁者看得比十個普通人還重要，不是嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예상은 했지만 겉잡을 수 없이 뒤틀렸군, 네놈은.","JPN":"予想はしていたがとてつもなくひねくれているな、貴様は。","ENG":"Just as I feared. You're beyond saving.","TWN":"雖然有預料到，但你的想法還真是扭曲。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"전갈자리의 기사, 피오네 로웰이 그대에게 묻겠다!","JPN":"蠍座の騎士、フィオネ・ローウェルがそなたに問う！","ENG":"Fione Lowell, the Knight of Scorpio, asks you!","TWN":"天蠍座騎士，菲奧尼·勞威爾向你發問！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그대는 무엇을 위해 싸우는가!","JPN":"そなたは何のために戦うのか！","ENG":"What do you fight for?!","TWN":"你為何而戰！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그대가 추구하는 정의란, 정녕 무엇인가!","JPN":"そなたが求めている正義とは、いったい何なのか！","ENG":"What is the justice you pursue?!","TWN":"你所追求的正義，究竟是什麼！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"힘. 그것으로부터 나오는 절대적 복종아래의 규율.","JPN":"力。それによる絶対的な服従のもとに成り立つ規律。","ENG":"Power. The discipline born from absolute obedience under that power.","TWN":"力量。由此可以孕育出能讓人絕對服從的法則。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_7"},{"id":"L47_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"지금부터 그것이 무엇인지 깨닫게 해주마, 로웰 가의 여식이여.","JPN":"今からそれを思い知らせてやろう、ローウェル家の娘。","ENG":"Let me show you exactly what that means, daughter of House Lowell.","TWN":"從現在開始，我會讓你明白那是什麼，勞威爾家的小姐。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_8"}]`);export{e as default};